using Microsoft.EntityFrameworkCore;

// Cosmos DB EF Core 9 breaking changes addressed below:
// 1. Discriminator property renamed from "Discriminator" to "$type" — existing docs use old name
// 2. id property no longer contains discriminator — existing docs have "EntityType|Key" format
// 3. Sync I/O no longer supported — must use async methods

class CosmosDbContext : DbContext
{
    public DbSet<Session> Sessions => Set<Session>();

    protected override void OnConfiguring(DbContextOptionsBuilder options)
    {
        options.UseCosmos(
            "AccountEndpoint=https://localhost:8081/;AccountKey=placeholder",
            "MyDatabase");
    }

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Session>(b =>
        {
            b.ToContainer("Sessions");

            // EF Core 9 breaking change: default discriminator property renamed to "$type".
            // Existing documents use "Discriminator" — explicitly preserve the old name.
            b.HasDiscriminator<string>("Discriminator");

            // EF Core 9 breaking change: id no longer includes discriminator prefix.
            // Existing documents have "Session|<key>" format — preserve for compatibility.
            b.HasRootDiscriminatorInJsonId(true);
        });
    }
}

class Session
{
    public string Id { get; set; } = default!;
    public string Title { get; set; } = default!;
}

// EF Core 9 breaking change: Cosmos DB provider no longer supports synchronous I/O.
// All sync calls (ToList, SaveChanges, etc.) must be replaced with async equivalents.
class CosmosQueryService
{
    private readonly CosmosDbContext _db;
    public CosmosQueryService(CosmosDbContext db) => _db = db;

    // BEFORE (EF Core 8 — sync, now throws in EF Core 9):
    //   var sessions = _db.Sessions.Where(s => s.Title != "").ToList();
    //   _db.SaveChanges();

    // AFTER (EF Core 9 — async required):
    public async Task<List<Session>> GetSessionsAsync()
    {
        return await _db.Sessions.Where(s => s.Title != "").ToListAsync();
    }

    public async Task SaveAsync()
    {
        await _db.SaveChangesAsync();
    }
}

